const db = require('./db'); // assume a database connection module

class Coupon {
  async apply(code) {
    const now = new Date();
    const coupon = await db.get(`coupons:${code}`);
    if (!coupon || coupon.expires < now) return false;
    
    const userCoupon = await db.get(`user_coupons:${this.userId}:${code}`);
    if (userCoupon) return false; // already used
    
    await db.set(`user_coupons:${this.userId}:${code}`, true);
    this.discount = coupon.discount;
    return true;
  }
}

